import hashlib

def clean_contamination(document_text, test_set_hashes):
    words = document_text.split()
    shingle_len = 13
    for i in range(len(words) - shingle_len + 1):
        shingle = " ".join(words[i:i+shingle_len])
        h = hashlib.sha256(shingle.encode('utf-8')).hexdigest()
        if h in test_set_hashes:
            return False  # Contaminated document
    return True

