def verify_commit_regression(current_scores, baseline_scores, tolerance=0.02):
    regressions = []
    for metric, score in current_scores.items():
        base = baseline_scores.get(metric, 1.0)
        if score < base - tolerance:
            regressions.append(f"{metric}: regressed from {base:.2f} to {score:.2f}")
    return regressions
